import React from "react";
import MasonryGrid from "./MasonryGrid";



const Galeria=()=>{
    return(

    <section className="min-h-[100vh] content-center justify-center">
        <div className="text-center">
            <h1 className="titulo-playfair font-semibold text-[#7D6239] text-[2rem]">¿Te quedaste con ganas de ver más?</h1>
            <div className="h-[5px] w-[3vh] mx-auto rounded-full bg-gradient-to-r from-[#CC2329] to-[#F55809]"></div>
        </div>
        <div className="w-[60%] mx-auto">
        <MasonryGrid />
      </div>

    </section>

    );
};

export default Galeria;
